static bool IsEnvironmentVariableDefined(string name)
{
    // IDictionary enumerates all defined vars; contains-key is
    // the only reliable "exists?" check on .NET 9 Linux.
    var vars = Environment.GetEnvironmentVariables();
    return vars.Contains(name);

